const appState = {
 currentTool: "brush",      // Aktuelles Werkzeug
 canvasLayers: [],          // Alle Ebenen der Zeichen-App
 selectedLayerId: null,     // Aktuell ausgewählte Ebene
 userPreferences: {         // Benutzereinstellungen
  brushSize: 5,
  color: "#000000"
 }
};

new Proxy(
 {
  a: 1,
  b: 2
 }, {
  set(target, prop, value) {
   target[prop] = value;
   return true;
  },
  get(target, prop) {
   console.log(`Abgefragte Daten: ${prop}`);
   return target[prop];
 },
 }
)

const createStore = initialState => {

 let state = initialState;

 return new Proxy({}, {
  get(target, prop) {
   return state[prop];
  },
  set(target, prop, value) {
   state = {...state, [prop]: value};
   return true;
  }
 })
}

const myStore = createStore({counter: 0});

document.querySelector('#inpNum').addEventListener('input', evt => {
 myStore.counter = parseInt(evt.target.value);
 console.log(myStore.counter);
})

const createStore = initialState => {

 let state = initialState;
 let views = [];

 const store = new Proxy({}, {
  get(target, prop) {
   return state[prop];
  },
  set(target, prop, value) {
   state = {...state, [prop]: value};

   views.forEach(v => {
    if (v.prop === prop)
     v.el.innerText = state[prop]
   });

   return true;
  }
 })

 const addView = (el, prop) => {
  views = [...views, {el, prop}];
 }

 const removeView = (el, prop) => {
  views = views.filter(v => v.el !== el && v.prop !== prop);
 }

 return {store, addView, removeView};
}

const myStore = createStore({counter: 0});

const h1 = document.createElement('h1');
h1.innerText = myStore.store.counter;
myStore.addView(h1, 'counter');
document.body.append(h1);

const inp = document.querySelector('#inpNum');
inp.value = myStore.store.counter;
inp.addEventListener('input', evt => {
 myStore.store.counter = parseInt(evt.target.value);
 console.log(myStore.store.counter);
})
